    features = "src/test/resources",
    glue = "org.apache.commons.collections.list.steps"
)
public class CucumberTest {
}

package org.apache.commons.collections.list.steps;

import io.cucumber.java.After;
import io.cucumber.java.Before;
import io.cucumber.java.en.*;
import org.apache.commons.collections.list.SetUniqueList;
import static org.junit.Assert.*;

public class StepDefs {

    private SetUniqueList<String> setUniqueList;

    @Before
    public void setUp() {
        setUniqueList = SetUniqueList.setUniqueList();
    }

    @After
    public void tearDown() {
        setUniqueList = null;
    }

    @Given("a SetUniqueList containing the strings {string}, {string}, {string}")
    public void a_SetUniqueList_containing_the_strings(String arg0, String arg1, String arg2) {
        setUniqueList.add(arg0);
        setUniqueList.add(arg1);
        setUniqueList.add(arg2);
    }

    @When("I set the element at index {int} to {string}")
    public void i_set_the_element_at_index_to(Integer index, String element) {
        setUniqueList.set(index, element);
    }

    @Then("the list should contain {string}, {string}, {string}")
    public void the_list_should_contain(String arg0, String arg1, String arg2) {
        assertEquals(arg0, setUniqueList.get(0));
        assertEquals(arg1, setUniqueList.get(1));
        assertEquals(arg2, setUniqueList.get(2));
    }

    @Then("the list size should be {int}")
    public void the_list_size_should_be(Integer expectedSize) {
        assertEquals(expectedSize.intValue(), setUniqueList.size());
    }

    @When("I attempt to add {string} at index {int}")
    public void i_attempt_to_add_at_index(String element, Integer index) {
        try {
            setUniqueList.add(index, element);
        } catch (Exception e) {
            // Exception caught if needed
        }
    }

    @Then("the list should still contain {string}, {string}, {string}")
    public void the_list_should_still_contain(String arg0, String arg1, String arg2) {
        assertEquals(arg0, setUniqueList.get(0));
        assertEquals(arg1, setUniqueList.get(1));
        assertEquals(arg2, setUniqueList.get(2));
    }

    @When("I attempt to add {string} at index {int}")
    public void i_attempt_to_add_unique_at_index(String element, Integer index) {
        setUniqueList.add(index, element);  // Adding unique element should work
    }
}

